class Message:
    def __init__(self, role, content):
        self.role = role
        self.content = content

    def to_dict(self):
        return {"role": self.role, "content": self.content}

    def __repr__(self):
        return f"Message(role={self.role!r}, content={self.content!r})"

m = Message("user", "Hello")
print(m)            # Message(role='user', content='Hello')
print(m.to_dict())  # {'role': 'user', 'content': 'Hello'}

class BadConversation:
    history = []                 # shared by ALL instances!
    def add(self, msg):
        self.history.append(msg)

class GoodConversation:
    def __init__(self):
        self.history = []        # per-instance
    def add(self, msg):
        self.history.append(msg)

a, b = BadConversation(), BadConversation()
a.add("hi")
print(b.history)   # ['hi'] -- leaked across instances!

x, y = GoodConversation(), GoodConversation()
x.add("hi")
print(y.history)   # [] -- isolated

class BaseTool:
    def __init__(self, name):
        self.name = name
    def run(self, **kwargs):
        raise NotImplementedError

class EchoTool(BaseTool):
    def __init__(self):
        super().__init__("echo")     # call parent initializer
    def run(self, text=""):
        return text

class Usage:
    def __init__(self, prompt, completion):
        self.prompt, self.completion = prompt, completion
    @property
    def total(self):
        return self.prompt + self.completion

print(EchoTool().run(text="hi"))   # hi
print(Usage(10, 5).total)          # 15  (no parentheses)

class SearchTool:
    def run(self, query):
        return f"results for {query}"

class WeatherTool:
    def run(self, query):
        return f"weather for {query}"

def dispatch(tool, query):
    return tool.run(query)        # doesn't care about the class

for tool in (SearchTool(), WeatherTool()):
    print(dispatch(tool, "Paris"))
